1	type Item = { type: string; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: QuoteStep[];
6	};
7	type QuoteResult = { premium: number };
8	
9	const PROCESSING_FEE = 5;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const withFirstInsurance = (base: number): number =>
22	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
23	
24	const CURSE_SURCHARGE_RATE = 0.5;
25	
26	const itemPremium = (item: Item): number => {
27	  const base = BASE_PREMIUMS[item.type];
28	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
29	  return withFirstInsurance(base) + curse;
30	};
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	const BLOCK_SIZE = 3;
34	const BLOCK_BASE_PREMIUM = 60;
35	
36	const countByType = (items: Item[]): Map<string, number> => {
37	  const counts = new Map<string, number>();
38	  for (const item of items) {
39	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
40	  }
41	  return counts;
42	};
43	
44	const groupBasePremium = (type: string, count: number): number =>
45	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
46	
47	const componentsBase = (components: Item[]): number => {
48	  let total = 0;
49	  for (const [type, count] of countByType(components)) {
50	    total += groupBasePremium(type, count);
51	  }
52	  return total;
53	};
54	
55	const LOYALTY_DISCOUNT_RATE = 0.2;
56	const LOYALTY_YEARS = 2;
57	
58	type Customer = { yearsWithMHPCO: number };
59	
60	const quotePremium = (step: QuoteStep, customer: Customer): QuoteResult => {
61	  const components = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
62	  const nonComponents = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
63	  const nonComponentTotal = nonComponents.reduce((sum, item) => sum + itemPremium(item), 0);
64	  const compBase = componentsBase(components);
65	  const componentTotal = withFirstInsurance(compBase);
66	  const nonComponentBase = nonComponents.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
67	  const policyBase = nonComponentBase + compBase;
68	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
69	  return { premium: Math.ceil(nonComponentTotal + componentTotal - loyalty + PROCESSING_FEE) };
70	};
71	
72	export const run = (scenario: Scenario): { results: QuoteResult[] } => {
73	  return { results: scenario.steps.map((step) => quotePremium(step, scenario.customer)) };
74	};
